-- Name: entities; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.entities (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    short_code character varying(10) NOT NULL,
    full_name character varying(150) NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: gatepasses; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.gatepasses (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    requester_id uuid NOT NULL,
    approver_id uuid,
    asset_ref character varying(150),
    purpose text NOT NULL,
    status character varying(30) DEFAULT 'pending'::character varying NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    origin_branch character varying(150),
    recipient_branch character varying(150),
    issue_date date,
    employee_name character varying(150),
    employee_code character varying(50),
    department_name character varying(150),
    contact_number character varying(50),
    asset_description text,
    issuer_signed_name character varying(150),
    issuer_signed_at timestamp with time zone,
    receiver_signed_name character varying(150),
    receiver_signed_at timestamp with time zone,
    security_signed_name character varying(150),
    security_signed_at timestamp with time zone,
    gatepass_number character varying(32),
    approver_name_text character varying(150),
    receiver_signed_file_name character varying(255),
    receiver_signed_file_content_type character varying(120),
    receiver_signed_file_data bytea,
    receiver_signed_file_uploaded_at timestamp with time zone,
    receiver_signed_file_uploaded_by uuid,
    receiver_signed_verification_status character varying(30) DEFAULT 'missing'::character varying NOT NULL,
    receiver_signed_verification_notes text
);


--
-- Name: hostname_sequences; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.hostname_sequences (
    entity_id uuid NOT NULL,
    dept_id uuid NOT NULL,
    next_seq integer DEFAULT 1 NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: inventory_stock; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.inventory_stock (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    sub_item_id uuid NOT NULL,
    branch_id uuid NOT NULL,
    quantity integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT inventory_stock_quantity_check CHECK ((quantity >= 0))
);


--
-- Name: inventory_stock_movements; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.inventory_stock_movements (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    sub_item_id uuid NOT NULL,
    asset_id uuid,
    operation character varying(20) NOT NULL,
    from_branch_id uuid,
    to_branch_id uuid,
    quantity integer NOT NULL,
    note text,
    actor_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT inventory_stock_movements_quantity_check CHECK ((quantity > 0))
);


--
-- Name: inventory_sync_runs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.inventory_sync_runs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    source_type character varying(40) NOT NULL,
    status character varying(20) NOT NULL,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    finished_at timestamp with time zone,
    records_seen integer DEFAULT 0 NOT NULL,
    records_upserted integer DEFAULT 0 NOT NULL,
    error_text text
);


--
-- Name: items; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.items (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(120) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: locations; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.locations (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    entity_id uuid NOT NULL,
    location_code character varying(30) NOT NULL,
    full_name character varying(150) NOT NULL,
    city character varying(80),
    state character varying(80),
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: patch_run_reports; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.patch_run_reports (
